send '(set -x ; eval "$(tmux display-message -p "#{session_name}" | tr "-" "\n")" ; while sleep 1 ; do date ; for port in $(seq $min $max ) ; do ssh -p $port gera@127.0.0.1 -N -L 127.0.0.1:$target:127.0.0.1:22 -oStrictHostKeyChecking=no -oUserKnownHostsFile=/dev/null -oServerAliveInterval=15 -oExitOnForwardFailure=yes -oConnectTimeout=8 -oConnectionAttempts=1 -oPasswordAuthentication=no ; done ; done)'
